(function(){
  // Very small DOMPurify-like sanitizer: removes <script> elements and attributes starting with 'on'
  function sanitize(html){
    if (!html) return '';
    try{
      const doc = new DOMParser().parseFromString(html, 'text/html');
      // remove script/style
      const scripts = doc.querySelectorAll('script,style');
      scripts.forEach(n => n.parentNode && n.parentNode.removeChild(n));
      // remove event handler attributes and javascript: hrefs
      const all = doc.querySelectorAll('*');
      all.forEach(el => {
        // remove on* attributes
        for (let i = el.attributes.length - 1; i >= 0; i--){
          const attr = el.attributes[i];
          if (/^on/i.test(attr.name)) el.removeAttribute(attr.name);
          if (attr.name === 'href' && /^javascript:/i.test(attr.value)) el.removeAttribute('href');
        }
      });
      return doc.body.innerHTML || '';
    }catch(e){
      return '';
    }
  }
  window.DOMPurify = window.DOMPurify || { sanitize: sanitize };
})();
